// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

/**
 * @title MockUSDC
 * @notice Test-only USDC with 6 decimals. Never deploy to mainnet.
 */
contract MockUSDC is ERC20, Ownable {
    constructor(address owner) ERC20("USD Coin", "USDC") Ownable(owner) {}

    function decimals() public pure override returns (uint8) { return 6; }

    function mint(address to, uint256 amount) external onlyOwner {
        _mint(to, amount);
    }

    function faucet(uint256 amount) external {
        require(amount <= 100_000 * 1e6, "MockUSDC: max 100K per faucet");
        _mint(msg.sender, amount);
    }
}

contracts/registry/IdentityRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "../interfaces/IIdentityRegistry.sol";

/**
 * @title IdentityRegistry
 * @notice On-chain KYC/AML registry for Issura platform.
 *
 *   - Compliance officers register and verify investor identities
 *   - Each identity stores country, tier, KYC hash, and expiry
 *   - Transfer compliance checks query this registry
 *   - Country allow-list enforces ASEAN geo-fencing
 *   - Supports annual re-verification (MAS requirement)
 *
 * @dev Role hierarchy:
 *   DEFAULT_ADMIN_ROLE  — platform deployer, can grant/revoke roles
 *   COMPLIANCE_ROLE     — KYC officers, can register/verify/suspend
 *   AGENT_ROLE          — token contracts, can call canTransfer()
 */
contract IdentityRegistry is IIdentityRegistry, AccessControl, Pausable {

    // ── Roles ──────────────────────────────────────────────────────────────
    bytes32 public constant COMPLIANCE_ROLE = keccak256("COMPLIANCE_ROLE");
    bytes32 public constant AGENT_ROLE      = keccak256("AGENT_ROLE");

    // ── Storage ────────────────────────────────────────────────────────────
    mapping(address => Identity) private _identities;
    mapping(uint16 => bool) private _allowedCountries;
    address[] private _investors; // ordered list for enumeration

    // ── Constructor ────────────────────────────────────────────────────────
    constructor(address admin, address complianceOfficer) {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(COMPLIANCE_ROLE, admin);
        _grantRole(COMPLIANCE_ROLE, complianceOfficer);

        // Pre-allow core ASEAN countries (ISO 3166-1 numeric)
        _allowedCountries[702] = true; // Singapore
        _allowedCountries[458] = true; // Malaysia
        _allowedCountries[360] = true; // Indonesia
        _allowedCountries[764] = true; // Thailand
        _allowedCountries[608] = true; // Philippines
        _allowedCountries[704] = true; // Vietnam
        _allowedCountries[784] = true; // UAE (common HNWI source)
        _allowedCountries[826] = true; // UK
        _allowedCountries[344] = true; // Hong Kong

        emit CountryAllowed(702);
        emit CountryAllowed(458);
        emit CountryAllowed(360);
        emit CountryAllowed(764);
        emit CountryAllowed(608);
    }

    // ── Compliance officer functions ───────────────────────────────────────

    /**
     * @notice Register a new investor identity (post-KYC approval off-chain)
     * @param investor  Wallet address
     * @param country   ISO 3166-1 numeric country code
     * @param tier      Verification tier (ACCREDITED / INSTITUTIONAL)
     * @param kycHash   keccak256 of off-chain KYC document bundle (privacy-preserving audit trail)
     */
    function registerIdentity(
        address investor,
        uint16 country,
        VerificationTier tier,
        bytes32 kycHash
    ) external override onlyRole(COMPLIANCE_ROLE) whenNotPaused {
        require(investor != address(0), "IR: zero address");
        require(_allowedCountries[country], "IR: country not allowed");
        require(tier != VerificationTier.NONE && tier != VerificationTier.PENDING, "IR: invalid tier");
        require(_identities[investor].wallet == address(0), "IR: already registered");

        uint48 now48 = uint48(block.timestamp);
        _identities[investor] = Identity({
            wallet:     investor,
            country:    country,
            tier:       tier,
            verifiedAt: now48,
            expiresAt:  now48 + 365 days,   // annual re-verification
            kycHash:    kycHash,
            amlClear:   true
        });
        _investors.push(investor);

        emit IdentityRegistered(investor, country, uint8(tier));
        emit IdentityVerified(investor);
    }

    /**
     * @notice Mark an existing pending identity as verified
     */
    function verifyIdentity(address investor)
        external override onlyRole(COMPLIANCE_ROLE) whenNotPaused
    {
        Identity storage id = _identities[investor];
        require(id.wallet != address(0), "IR: not registered");
        id.tier = VerificationTier.ACCREDITED;
        id.verifiedAt = uint48(block.timestamp);
        id.expiresAt  = uint48(block.timestamp) + 365 days;
        emit IdentityVerified(investor);
    }

    /**
     * @notice Suspend investor — freezes all transfer capability
     * @param reason  Human-readable reason (stored in event for audit trail)
     */
    function suspendIdentity(address investor, string calldata reason)
        external override onlyRole(COMPLIANCE_ROLE)
    {
        Identity storage id = _identities[investor];
        require(id.wallet != address(0), "IR: not registered");
        id.tier = VerificationTier.SUSPENDED;
        emit IdentitySuspended(investor, reason);
    }

    /**
     * @notice Remove identity entirely (GDPR right-to-erasure — removes on-chain pointer, off-chain data purged separately)
     */
    function removeIdentity(address investor)
        external override onlyRole(COMPLIANCE_ROLE)
    {
        require(_identities[investor].wallet != address(0), "IR: not registered");
        delete _identities[investor];
        emit IdentityRemoved(investor);
    }

    /**
     * @notice Update KYC expiry after annual re-verification
     */
    function updateKycExpiry(address investor, uint48 newExpiry)
        external override onlyRole(COMPLIANCE_ROLE)
    {
        require(_identities[investor].wallet != address(0), "IR: not registered");
        require(newExpiry > block.timestamp, "IR: expiry in past");
        _identities[investor].expiresAt = newExpiry;
    }

    /**
     * @notice Toggle country allow-list
     */
    function setCountryAllowed(uint16 country, bool allowed)
        external override onlyRole(DEFAULT_ADMIN_ROLE)
    {
        _allowedCountries[country] = allowed;
        if (allowed) emit CountryAllowed(country);
        else emit CountryBlocked(country);
    }

    // ── Read functions ─────────────────────────────────────────────────────

    function isVerified(address investor) public view override returns (bool) {
        Identity storage id = _identities[investor];
        return
            id.wallet != address(0) &&
            (id.tier == VerificationTier.ACCREDITED || id.tier == VerificationTier.INSTITUTIONAL) &&
            id.amlClear &&
            id.expiresAt > block.timestamp;
    }

    function getIdentity(address investor)
        external view override returns (Identity memory)
    {
        return _identities[investor];
    }

    function isCountryAllowed(uint16 country)
        external view override returns (bool)
    {
        return _allowedCountries[country];
    }

    /**
     * @notice Core compliance check called by token contracts before every transfer
     * @return bool  Whether transfer is permitted
     */
    function canTransfer(address from, address to)
        external view override returns (bool)
    {
        // Minting (from == 0) only requires receiver to be verified
        if (from == address(0)) return isVerified(to);
        // Burning (to == 0) always allowed for compliance-triggered burns
        if (to == address(0)) return true;
        return isVerified(from) && isVerified(to);
    }

    // ── Admin ──────────────────────────────────────────────────────────────

    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) { _pause(); }
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) { _unpause(); }

    function investorCount() external view returns (uint256) {
        return _investors.length;
    }

    function getInvestorAt(uint256 index) external view returns (address) {
        return _investors[index];
    }
}

contracts/STOFactory.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./tokens/IssuraSecurityToken.sol";

/**
 * @title STOFactory
 * @notice Platform-level factory that deploys a new IssuraSecurityToken
 *         for each approved STO. Acts as the single entry point for
 *         issuer onboarding and token lifecycle management.
 *
 *   Flow:
 *     1. Admin approves issuer application (off-chain KYC complete)
 *     2. Admin calls createSTO() with config approved in review
 *     3. New IssuraSecurityToken (ERC-1400) deployed and registered
 *     4. Investors call invest() via the factory (AGENT_ROLE)
 *     5. Issuer calls processDistribution() directly on token contract
 *
 * @dev Only ADMIN_ROLE can create STOs (gated — no permissionless issuance)
 */
contract STOFactory is AccessControl, ReentrancyGuard {

    // ── Roles ──────────────────────────────────────────────────────────────
    bytes32 public constant OPERATOR_ROLE   = keccak256("OPERATOR_ROLE");
    bytes32 public constant COMPLIANCE_ROLE = keccak256("COMPLIANCE_ROLE");

    // ── State ──────────────────────────────────────────────────────────────
    address public immutable identityRegistry;
    address public immutable usdc;
    address public feeTreasury;
    uint16  public defaultFeeBps = 150; // 1.5% platform fee

    struct STORecord {
        address tokenAddress;
        address issuer;
        string  name;
        string  assetType;
        uint256 targetRaise;
        uint48  createdAt;
        bool    active;
    }

    mapping(bytes32 => STORecord) public stoRecords;  // stoId => record
    mapping(address => bytes32[]) public issuerSTOs;  // issuer => stoIds
    bytes32[] public allSTOIds;

    uint256 public stoCount;

    // ── Events ─────────────────────────────────────────────────────────────
    event STOCreated(
        bytes32 indexed stoId,
        address indexed tokenAddress,
        address indexed issuer,
        string name,
        string assetType,
        uint256 targetRaise
    );
    event STODeactivated(bytes32 indexed stoId, string reason);
    event InvestmentProcessed(
        bytes32 indexed stoId,
        address indexed investor,
        uint256 indexed usdcAmount,
        uint256 tokens
    );
    event FeeTreasuryUpdated(address indexed oldTreasury, address indexed newTreasury);
    event DefaultFeeUpdated(uint16 indexed oldBps, uint16 indexed newBps);

    // ── Constructor ────────────────────────────────────────────────────────
    constructor(
        address identityRegistry_,
        address usdc_,
        address feeTreasury_,
        address admin,
        address operator
    ) {
        require(identityRegistry_ != address(0), "Factory: zero registry");
        require(usdc_ != address(0), "Factory: zero usdc");
        require(feeTreasury_ != address(0), "Factory: zero treasury");
        identityRegistry = identityRegistry_;
        usdc = usdc_;
        feeTreasury = feeTreasury_;

        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(OPERATOR_ROLE, admin);
        _grantRole(OPERATOR_ROLE, operator);
        _grantRole(COMPLIANCE_ROLE, admin);
    }

    // ── STO Creation (admin/operator only — gated platform) ────────────────

    /**
     * @notice Deploy a new security token for an approved STO.
     * @param config  Full STO configuration (reviewed and approved off-chain)
     * @param complianceOfficer  Address authorized to freeze/force-transfer
     * @return stoId         Unique identifier for this STO
     * @return tokenAddress  Deployed token contract address
     */
    function createSTO(
        IssuraSecurityToken.STOConfig calldata config,
        address complianceOfficer
    )
        external
        onlyRole(OPERATOR_ROLE)
        returns (bytes32 stoId, address tokenAddress)
    {
        require(config.issuer != address(0), "Factory: zero issuer");
        require(config.treasury != address(0), "Factory: zero treasury");
        require(config.targetRaise > 0, "Factory: zero target");
        require(config.tokenPrice > 0, "Factory: zero price");
        require(config.maxSupply > 0, "Factory: zero supply");
        require(config.closingDate > block.timestamp, "Factory: closing date in past");
        require(config.allowedCountries.length > 0, "Factory: no countries");

        // Generate unique STO ID
        stoId = keccak256(abi.encodePacked(
            config.issuer,
            config.name,
            block.timestamp,
            stoCount
        ));

        // Deploy token contract
        IssuraSecurityToken token = new IssuraSecurityToken(
            config,
            identityRegistry,
            usdc,
            address(this),       // factory is admin
            complianceOfficer
        );

        tokenAddress = address(token);

        // Record
        stoRecords[stoId] = STORecord({
            tokenAddress: tokenAddress,
            issuer:       config.issuer,
            name:         config.name,
            assetType:    config.assetType,
            targetRaise:  config.targetRaise,
            createdAt:    uint48(block.timestamp),
            active:       true
        });

        issuerSTOs[config.issuer].push(stoId);
        allSTOIds.push(stoId);
        ++stoCount;

        emit STOCreated(stoId, tokenAddress, config.issuer, config.name, config.assetType, config.targetRaise);
    }

    // ── Investment routing ─────────────────────────────────────────────────

    /**
     * @notice Route an investor's USDC into a specific STO.
     *         Factory acts as AGENT — verifies everything then calls invest().
     *
     *         Investor must have:
     *           1. Approved USDC allowance to this factory
     *           2. Verified identity in IdentityRegistry
     *
     * @param stoId      Target STO
     * @param usdcAmount USDC amount (6 decimals)
     */
    function invest(bytes32 stoId, uint256 usdcAmount)
        external
        nonReentrant
    {
        STORecord storage rec = stoRecords[stoId];
        require(rec.active, "Factory: STO not active");
        require(rec.tokenAddress != address(0), "Factory: STO not found");

        IssuraSecurityToken token = IssuraSecurityToken(rec.tokenAddress);

        // Transfer USDC from investor to factory first
        IERC20 usdcToken = IERC20(usdc);
        require(
            usdcToken.transferFrom(msg.sender, address(this), usdcAmount),
            "Factory: USDC transfer failed"
        );

        // Approve token contract to pull exactly usdcAmount from factory
        // Using forceApprove pattern: reset to 0 first (some tokens require this)
        bool s1 = usdcToken.approve(rec.tokenAddress, 0);
        bool s2 = usdcToken.approve(rec.tokenAddress, usdcAmount);

        // Delegate to token contract — it will pull from this factory
        token.invest(msg.sender, usdcAmount);

        // Reset approval to 0 after call — prevents stale allowance exploit
        bool s3 = usdcToken.approve(rec.tokenAddress, 0);

        emit InvestmentProcessed(stoId, msg.sender, usdcAmount, 0);
    }

    // ── Admin ──────────────────────────────────────────────────────────────

    function deactivateSTO(bytes32 stoId, string calldata reason)
        external onlyRole(COMPLIANCE_ROLE)
    {
        stoRecords[stoId].active = false;
        emit STODeactivated(stoId, reason);
    }

    function setFeeTreasury(address newTreasury)
        external onlyRole(DEFAULT_ADMIN_ROLE)
    {
        require(newTreasury != address(0), "Factory: zero address");
        emit FeeTreasuryUpdated(feeTreasury, newTreasury);
        feeTreasury = newTreasury;
    }

    function setDefaultFeeBps(uint16 newBps)
        external onlyRole(DEFAULT_ADMIN_ROLE)
    {
        require(newBps <= 500, "Factory: fee too high"); // max 5%
        emit DefaultFeeUpdated(defaultFeeBps, newBps);
        defaultFeeBps = newBps;
    }

    // ── Views ──────────────────────────────────────────────────────────────

    function getSTORecord(bytes32 stoId)
        external view returns (STORecord memory)
    {
        return stoRecords[stoId];
    }

    function getIssuerSTOs(address issuer)
        external view returns (bytes32[] memory)
    {
        return issuerSTOs[issuer];
    }

    function getAllSTOIds() external view returns (bytes32[] memory) {
        return allSTOIds;
    }
}

contracts/tokens/ISSToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title ISSToken
 * @notice Issura Platform Utility Token (ISS)
 *
 *   Fixed supply: 100,000,000 ISS (no mint after deployment)
 *   Non-security: confers no ownership, dividends, or governance rights
 *   over platform revenues. Utility only — fee discounts and staking.
 *
 *   Utility functions:
 *   1. Fee discounts: pay issuance fees in ISS → 20-50% discount
 *   2. Staking: lock ISS → earn platform credits, priority queue access
 *   3. Burn: 20% of ISS used for fees is burned (deflationary)
 *
 *   Token allocation (set at deploy, distributed by admin):
 *   - 50% Liquidity provision (50M)
 *   - 25% Ecosystem & growth fund (25M)
 *   - 15% Team & advisors — vested (15M)
 *   - 10% Strategic partnerships & reserve (10M)
 */
contract ISSToken is ERC20, AccessControl, ReentrancyGuard {

    // ── Roles ──────────────────────────────────────────────────────────────
    bytes32 public constant PLATFORM_ROLE = keccak256("PLATFORM_ROLE");

    // ── Constants ──────────────────────────────────────────────────────────
    uint256 public constant MAX_SUPPLY     = 100_000_000 * 1e18;
    uint256 public constant BURN_RATE_BPS  = 2000; // 20% of fees paid in ISS

    // ── Staking ────────────────────────────────────────────────────────────
    struct Stake {
        uint256 amount;
        uint48  stakedAt;
        uint48  lockUntil;   // 3, 6, or 12 month options
        uint48  lastReward;
        bool    active;
    }

    mapping(address => Stake) public stakes;
    uint256 public totalStaked;
    uint256 public constant EARLY_UNSTAKE_PENALTY_BPS = 2500; // 25% slashed to burn

    // Staking lock durations
    uint48 public constant LOCK_3M  = 90  days;
    uint48 public constant LOCK_6M  = 180 days;
    uint48 public constant LOCK_12M = 365 days;

    // ── Vesting (team/advisor allocation) ─────────────────────────────────
    struct VestingSchedule {
        uint256 total;
        uint256 claimed;
        uint48  cliffEnd;
        uint48  vestEnd;
        bool    active;
    }
    mapping(address => VestingSchedule) public vestingSchedules;

    // ── Fee discount tiers ─────────────────────────────────────────────────
    // Staked amount thresholds for fee discount tiers
    uint256 public constant TIER1_STAKE =  1_000 * 1e18; // 20% discount
    uint256 public constant TIER2_STAKE =  5_000 * 1e18; // 35% discount
    uint256 public constant TIER3_STAKE = 10_000 * 1e18; // 50% discount

    // ── Events ─────────────────────────────────────────────────────────────
    event Staked(address indexed user, uint256 indexed amount, uint48 indexed lockUntil);
    event Unstaked(address indexed user, uint256 indexed amount, uint256 indexed penalty);
    event RewardClaimed(address indexed user, uint256 indexed creditAmount);
    event TokensBurned(address indexed from, uint256 indexed amount, string reason);
    event VestingCreated(address indexed beneficiary, uint256 indexed total, uint48 indexed cliffEnd, uint48 vestEnd);
    event VestingClaimed(address indexed beneficiary, uint256 indexed amount);

    // ── Constructor ────────────────────────────────────────────────────────
    constructor(
        address admin,
        address liquidityWallet,    // 50M — immediate
        address ecosystemWallet,    // 25M — linear 36 months
        address teamWallet,         // 15M — 12mo cliff + 36mo vest (held in contract)
        address partnershipWallet   // 10M — locked 24 months (held in contract)
    ) ERC20("Issura Utility Token", "ISS") {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(PLATFORM_ROLE, admin);

        // Mint total supply to this contract first — distribute from here
        _mint(address(this), MAX_SUPPLY);

        // 1. Liquidity (50M) — transfer immediately to liquidity wallet
        _transfer(address(this), liquidityWallet, 50_000_000 * 1e18);

        // 2. Ecosystem fund (25M) — transfer immediately; managed off-chain with multi-sig
        _transfer(address(this), ecosystemWallet, 25_000_000 * 1e18);

        // 3. Team (15M) — stays in contract; 12 month cliff, then 36 month linear vest
        // Do NOT transfer to teamWallet — claimVested() releases from contract
        vestingSchedules[teamWallet] = VestingSchedule({
            total:    15_000_000 * 1e18,
            claimed:  0,
            cliffEnd: uint48(block.timestamp) + 365 days,
            vestEnd:  uint48(block.timestamp) + 365 days + 3 * 365 days,
            active:   true
        });
        emit VestingCreated(teamWallet, 15_000_000 * 1e18,
            uint48(block.timestamp) + 365 days,
            uint48(block.timestamp) + 4 * 365 days);

        // 4. Partnerships & reserve (10M) — stays in contract; locked 24 months then linear 24 months
        // Do NOT transfer to partnershipWallet — claimVested() releases from contract
        vestingSchedules[partnershipWallet] = VestingSchedule({
            total:    10_000_000 * 1e18,
            claimed:  0,
            cliffEnd: uint48(block.timestamp) + 2 * 365 days,
            vestEnd:  uint48(block.timestamp) + 4 * 365 days,
            active:   true
        });
        emit VestingCreated(partnershipWallet, 10_000_000 * 1e18,
            uint48(block.timestamp) + 2 * 365 days,
            uint48(block.timestamp) + 4 * 365 days);

        // Sanity check: contract holds exactly vested portion (25M)
        // 50M liquidity + 25M ecosystem already sent out; 25M remains for vesting
        require(
            balanceOf(address(this)) == 25_000_000 * 1e18,
            "ISS: vesting balance mismatch"
        );
    }

    // ── Staking ────────────────────────────────────────────────────────────

    /**
     * @notice Stake ISS tokens for platform benefits.
     * @param amount    ISS amount to stake (18 decimals)
     * @param lockDays  Lock period: 90, 180, or 365 days
     */
    function stake(uint256 amount, uint48 lockDays) external nonReentrant {
        require(amount > 0, "ISS: zero amount");
        require(
            lockDays == LOCK_3M || lockDays == LOCK_6M || lockDays == LOCK_12M,
            "ISS: invalid lock period"
        );
        require(!stakes[msg.sender].active, "ISS: already staking");
        require(balanceOf(msg.sender) >= amount, "ISS: insufficient balance");

        _transfer(msg.sender, address(this), amount);
        stakes[msg.sender] = Stake({
            amount:     amount,
            stakedAt:   uint48(block.timestamp),
            lockUntil:  uint48(block.timestamp) + lockDays,
            lastReward: uint48(block.timestamp),
            active:     true
        });
        totalStaked += amount;

        emit Staked(msg.sender, amount, uint48(block.timestamp) + lockDays);
    }

    /**
     * @notice Unstake ISS. Early unstake incurs 25% penalty burned.
     */
    function unstake() external nonReentrant {
        Stake storage s = stakes[msg.sender];
        require(s.active, "ISS: no active stake");

        uint256 amount = s.amount;
        uint256 penalty = 0;

        if (block.timestamp < s.lockUntil) {
            // Early unstake: 25% slashed
            penalty = (amount * EARLY_UNSTAKE_PENALTY_BPS) / 10000;
            _burn(address(this), penalty);
            emit TokensBurned(msg.sender, penalty, "early_unstake_penalty");
        }

        uint256 returned = amount - penalty;
        s.active = false;
        s.amount = 0;
        totalStaked -= amount;

        _transfer(address(this), msg.sender, returned);
        emit Unstaked(msg.sender, returned, penalty);
    }

    // ── Fee discount query ─────────────────────────────────────────────────

    /**
     * @notice Returns the fee discount (in BPS) for a given address based on stake.
     * @return discountBps  0 = no discount, 2000 = 20%, 3500 = 35%, 5000 = 50%
     */
    function getFeeDiscount(address user) external view returns (uint256 discountBps) {
        Stake storage s = stakes[user];
        if (!s.active) return 0;
        if (s.amount >= TIER3_STAKE) return 5000;
        if (s.amount >= TIER2_STAKE) return 3500;
        if (s.amount >= TIER1_STAKE) return 2000;
        return 0;
    }

    /**
     * @notice Check if user has priority queue access (≥10,000 ISS staked for ≥6 months)
     */
    function hasPriorityAccess(address user) external view returns (bool) {
        Stake storage s = stakes[user];
        return s.active &&
               s.amount >= TIER3_STAKE &&
               s.lockUntil >= uint48(block.timestamp) + LOCK_6M;
    }

    // ── Platform fee burn (called by platform on fee settlement in ISS) ────

    /**
     * @notice Platform calls this when a user pays fees in ISS.
     *         Burns 20% of the ISS used; remaining 80% goes to ecosystem pool.
     * @param from    User paying fees in ISS
     * @param amount  Total ISS used for fee payment
     */
    function processFeePayment(address from, uint256 amount)
        external onlyRole(PLATFORM_ROLE)
    {
        require(balanceOf(from) >= amount, "ISS: insufficient fee bal");

        uint256 burnAmount = (amount * BURN_RATE_BPS) / 10000; // 20%
        // uint256 recycleAmount = amount - burnAmount;  // 80% — reserved for future staking pool

        // Pull from user
        _transfer(from, address(this), amount);

        // Burn 20%
        _burn(address(this), burnAmount);
        emit TokensBurned(from, burnAmount, "fee_payment");

        // Recycle 80% stays in contract as ecosystem/staking pool
        // (distributed via off-chain snapshot + airdrop for simplicity at MVP)
    }

    // ── Vesting ────────────────────────────────────────────────────────────

    /**
     * @notice Claim vested tokens (team/advisor/partnership wallets).
     */
    function claimVested() external nonReentrant {
        VestingSchedule storage v = vestingSchedules[msg.sender];
        require(v.active, "ISS: no vesting schedule");
        require(block.timestamp >= v.cliffEnd, "ISS: cliff not reached");

        uint256 vested = _vestedAmount(v);
        uint256 claimable = vested - v.claimed;
        require(claimable > 0, "ISS: nothing to claim");

        v.claimed += claimable;
        _transfer(address(this), msg.sender, claimable);
        emit VestingClaimed(msg.sender, claimable);
    }

    function _vestedAmount(VestingSchedule storage v)
        internal view returns (uint256)
    {
        if (block.timestamp < v.cliffEnd) return 0;
        if (block.timestamp >= v.vestEnd) return v.total;
        uint256 elapsed = block.timestamp - v.cliffEnd;
        uint256 duration = v.vestEnd - v.cliffEnd;
        return (v.total * elapsed) / duration;
    }

    function vestedAmount(address beneficiary) external view returns (uint256) {
        VestingSchedule storage v = vestingSchedules[beneficiary];
        if (!v.active) return 0;
        return _vestedAmount(v);
    }

    // ── Admin ──────────────────────────────────────────────────────────────

    function grantPlatformRole(address account)
        external onlyRole(DEFAULT_ADMIN_ROLE)
    {
        _grantRole(PLATFORM_ROLE, account);
    }
}

contracts/tokens/IssuraSecurityToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Pausable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "../interfaces/IIdentityRegistry.sol";
import "../interfaces/ISecurityToken.sol";
import "../interfaces/ISURAInvestable.sol";

/**
 * @title IssuraSecurityToken
 * @notice ERC-3643 compliant security token for a single STO.
 *
 *   Each STO on the Issura platform deploys its own instance of this
 *   contract via the STOFactory. Tokens represent fractional ownership
 *   of the underlying real-world asset.
 *
 *   Key compliance features:
 *   - Every transfer validated against IdentityRegistry
 *   - Geo-fencing: only investors in allowed countries
 *   - Forced transfer / freeze for regulatory compliance
 *   - USDC-based distribution with per-token claim model
 *   - Pausable for emergency or regulatory holds
 *
 * @dev Roles:
 *   DEFAULT_ADMIN_ROLE — platform admin
 *   COMPLIANCE_ROLE    — compliance officers (freeze, force transfer)
 *   ISSUER_ROLE        — issuer (process distributions)
 *   AGENT_ROLE         — platform agent (mint during investment)
 */
contract IssuraSecurityToken is
    ERC20,
    ERC20Pausable,
    AccessControl,
    ReentrancyGuard,
    ISecurityToken,
    ISURAInvestable
{
    // ── Roles ──────────────────────────────────────────────────────────────
    bytes32 public constant COMPLIANCE_ROLE = keccak256("COMPLIANCE_ROLE");
    bytes32 public constant ISSUER_ROLE     = keccak256("ISSUER_ROLE");
    bytes32 public constant AGENT_ROLE      = keccak256("AGENT_ROLE");

    // ── Interfaces ─────────────────────────────────────────────────────────
    IIdentityRegistry public immutable identityRegistry;
    IERC20 public immutable usdc; // USDC on Arbitrum: 0xaf88d065e77c8cC2239327C5EDb3A432268e5831

    // ── STO Config ─────────────────────────────────────────────────────────
    STOConfig private _config;
    bool public offeringClosed;
    string public pauseReason;

    // ── Investor tracking ──────────────────────────────────────────────────
    mapping(address => uint256) private _frozenTokens;
    mapping(address => bool) private _isInvestor;
    address[] private _investorList;
    uint256 private _investorCount;
    uint256 private _totalRaised; // in USDC (6 decimals)

    // ── Distribution state ─────────────────────────────────────────────────
    // Uses a "dividend per share" accumulator pattern — O(1) claims
    uint256 private _distributionIndex;           // scaled by 1e18
    mapping(address => uint256) private _investorIndex;
    mapping(address => uint256) private _pendingClaims;

    // ── Events (additional to interface) ───────────────────────────────────
    event Investment(address indexed investor, uint256 indexed usdcAmount, uint256 indexed tokens);
    event OfferingClosed(uint256 indexed totalRaised, uint256 indexed totalTokens);

    // ── Constructor ────────────────────────────────────────────────────────
    constructor(
        STOConfig memory config,
        address identityRegistry_,
        address usdc_,
        address admin,
        address complianceOfficer
    ) ERC20(config.name, config.symbol) {
        _config = config;
        identityRegistry = IIdentityRegistry(identityRegistry_);
        usdc = IERC20(usdc_);

        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(COMPLIANCE_ROLE, admin);
        _grantRole(COMPLIANCE_ROLE, complianceOfficer);
        _grantRole(ISSUER_ROLE, config.issuer);
        _grantRole(AGENT_ROLE, admin);
    }

    // ── Investment ─────────────────────────────────────────────────────────

    /**
     * @notice Investor purchases tokens during the offering period.
     * @param investor   Verified investor wallet (for token minting and compliance checks)
     * @param usdcAmount Amount of USDC to invest (6 decimals)
     *
     * Flow (called by STOFactory which already holds the USDC):
     *   1. Compliance check (identity registry)
     *   2. Calculate tokens from USDC / tokenPrice
     *   3. Pull USDC from msg.sender (factory) — factory already received it from investor
     *   4. Deduct platform fee → fee treasury
     *   5. Forward net proceeds → issuer treasury
     *   6. Mint security tokens to investor
     */
    function invest(address investor, uint256 usdcAmount)
        external
        onlyRole(AGENT_ROLE)
        whenNotPaused
        nonReentrant
    {
        require(!offeringClosed, "ST: offering closed");
        require(block.timestamp <= _config.closingDate, "ST: offering expired");
        require(
            identityRegistry.canTransfer(address(0), investor),
            "ST: investor not verified"
        );

        uint256 tokens = (usdcAmount * 1e18) / _config.tokenPrice;
        require(tokens >= _config.minInvestment, "ST: below minimum investment");
        require(totalSupply() + tokens <= _config.maxSupply, "ST: exceeds max supply");

        // Platform fee deduction
        uint256 fee        = (usdcAmount * _config.feeBps) / 10000;
        uint256 netProceeds = usdcAmount - fee;

        // Pull total USDC from factory (factory already received it from investor)
        // Factory approves this contract before calling invest()
        require(
            usdc.transferFrom(msg.sender, address(this), usdcAmount),
            "ST: USDC pull failed"
        );

        // Forward fee to platform treasury
        require(
            usdc.transfer(_config.treasury, fee),
            "ST: fee transfer failed"
        );

        // Forward net proceeds to issuer treasury
        require(
            usdc.transfer(_config.issuer, netProceeds),
            "ST: proceeds transfer failed"
        );

        // Update distribution index for new investor before minting
        _updateInvestorIndex(investor);

        // Mint tokens
        _mint(investor, tokens);
        _totalRaised += usdcAmount;

        // Track investor
        if (!_isInvestor[investor]) {
            _isInvestor[investor] = true;
            _investorList.push(investor);
            ++_investorCount;
        }

        emit Investment(investor, usdcAmount, tokens);
    }

    // ── Compliance Transfer Hooks ──────────────────────────────────────────

    /**
     * @dev Override ERC20 _update to enforce compliance on every transfer.
     *      Called by transfer(), transferFrom(), mint(), burn().
     */
    function _update(address from, address to, uint256 amount)
        internal
        override(ERC20, ERC20Pausable)
    {
        // Skip compliance checks for minting/burning (handled at call site)
        if (from != address(0) && to != address(0)) {
            require(
                identityRegistry.canTransfer(from, to),
                "ST: transfer not compliant"
            );
            // Respect frozen balances
            require(
                balanceOf(from) - _frozenTokens[from] >= amount,
                "ST: insufficient unfrozen"
            );
            // Update distribution indices before balance changes
            _updateInvestorIndex(from);
            _updateInvestorIndex(to);
        }
        super._update(from, to, amount);
    }

    // ── Compliance Functions ───────────────────────────────────────────────

    function forcedTransfer(
        address from,
        address to,
        uint256 amount,
        string calldata reason
    ) external override onlyRole(COMPLIANCE_ROLE) {
        require(balanceOf(from) >= amount, "ST: insufficient balance");
        _updateInvestorIndex(from);
        _updateInvestorIndex(to);
        _transfer(from, to, amount);
        emit ForcedTransfer(from, to, amount, reason);
    }

    function freezeTokens(address investor, uint256 amount)
        external override onlyRole(COMPLIANCE_ROLE)
    {
        require(balanceOf(investor) >= _frozenTokens[investor] + amount, "ST: insufficient balance");
        _frozenTokens[investor] += amount;
        emit TokensFrozen(investor, amount);
    }

    function unfreezeTokens(address investor, uint256 amount)
        external override onlyRole(COMPLIANCE_ROLE)
    {
        require(_frozenTokens[investor] >= amount, "ST: insufficient frozen");
        _frozenTokens[investor] -= amount;
        emit TokensUnfrozen(investor, amount);
    }

    /**
     * @notice Recover tokens from a lost/compromised wallet to a new verified wallet.
     *         Requires both old wallet suspension and new wallet verification.
     */
    function recoverTokens(address lostWallet, address newWallet)
        external override onlyRole(COMPLIANCE_ROLE)
    {
        require(identityRegistry.isVerified(newWallet), "ST: new wallet not verified");
        uint256 amount = balanceOf(lostWallet);
        require(amount > 0, "ST: no tokens to recover");
        _updateInvestorIndex(lostWallet);
        _updateInvestorIndex(newWallet);
        _transfer(lostWallet, newWallet, amount);
        // Transfer any pending distributions
        _pendingClaims[newWallet] += _pendingClaims[lostWallet];
        _pendingClaims[lostWallet] = 0;
        emit TokensRecovered(lostWallet, newWallet, amount);
    }

    // ── Lifecycle ──────────────────────────────────────────────────────────

    function pause(string calldata reason) external override onlyRole(COMPLIANCE_ROLE) {
        pauseReason = reason;
        _pause();
        emit STOPaused(reason);
    }

    function unpause() external override onlyRole(DEFAULT_ADMIN_ROLE) {
        pauseReason = "";
        _unpause();
        emit STOResumed();
    }

    function closeOffering() external override onlyRole(ISSUER_ROLE) {
        require(!offeringClosed, "ST: already closed");
        offeringClosed = true;
        emit OfferingClosed(_totalRaised, totalSupply());
    }

    // ── Distributions ──────────────────────────────────────────────────────

    /**
     * @notice Issuer deposits USDC yield/rent/dividends for all token holders.
     *         Uses accumulator pattern: O(1) deposit, O(1) claim per investor.
     * @param totalUSDC  Total USDC to distribute (must be pre-approved)
     */
    function processDistribution(uint256 totalUSDC)
        external override onlyRole(ISSUER_ROLE) nonReentrant
    {
        require(totalSupply() > 0, "ST: no tokens outstanding");
        require(totalUSDC > 0, "ST: zero distribution");

        require(
            usdc.transferFrom(msg.sender, address(this), totalUSDC),
            "ST: USDC transfer failed"
        );

        // Increment global index: how much USDC per token (scaled 1e18)
        uint256 increment = (totalUSDC * 1e18) / totalSupply();
        _distributionIndex += increment;

        // perToken for event: scale totalUSDC by 1e18, divide by totalSupply (18-decimal tokens)
        // Result is in USDC base units (6 decimals) per full token
        uint256 perToken = (totalUSDC * 1e18) / totalSupply();
        emit DistributionProcessed(totalUSDC, perToken, uint48(block.timestamp));
    }

    /**
     * @notice Investor claims their share of accumulated distributions.
     */
    function claimDistribution() external override nonReentrant whenNotPaused {
        _updateInvestorIndex(msg.sender);
        uint256 amount = _pendingClaims[msg.sender];
        require(amount > 0, "ST: nothing to claim");
        _pendingClaims[msg.sender] = 0;
        require(usdc.transfer(msg.sender, amount), "ST: claim transfer failed");
    }

    /**
     * @notice View pending unclaimed distributions for an investor.
     */
    function pendingDistribution(address investor)
        external view override returns (uint256)
    {
        uint256 delta = _distributionIndex - _investorIndex[investor];
        uint256 accrued = (balanceOf(investor) * delta) / 1e18;
        return _pendingClaims[investor] + accrued;
    }

    // ── Internal ───────────────────────────────────────────────────────────

    function _updateInvestorIndex(address investor) internal {
        uint256 delta = _distributionIndex - _investorIndex[investor];
        if (delta > 0 && balanceOf(investor) > 0) {
            _pendingClaims[investor] += (balanceOf(investor) * delta) / 1e18;
        }
        _investorIndex[investor] = _distributionIndex;
    }

    // ── Read ───────────────────────────────────────────────────────────────

    function getConfig() external view override returns (STOConfig memory) {
        return _config;
    }

    function isFrozen(address investor) external view override returns (bool) {
        return _frozenTokens[investor] > 0;
    }

    function frozenBalance(address investor) external view override returns (uint256) {
        return _frozenTokens[investor];
    }

    function totalRaised() external view override returns (uint256) {
        return _totalRaised;
    }

    function investorCount() external view override returns (uint256) {
        return _investorCount;
    }

    function canTransfer(address from, address to, uint256 amount)
        external view override returns (bool, string memory)
    {
        if (paused()) return (false, "STO is paused");
        if (!identityRegistry.canTransfer(from, to)) return (false, "Compliance check failed");
        if (balanceOf(from) - _frozenTokens[from] < amount) return (false, "Insufficient unfrozen balance");
        return (true, "");
    }

    function decimals() public pure override returns (uint8) {
        return 18;
    }
}

contracts/tokens/SURAToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/ERC20Pausable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "../interfaces/IIdentityRegistry.sol";
import "../interfaces/ISURAInvestable.sol";

/**
 * @title SURAToken
 * @notice SURA — Issura Platform Security Token (ERC-1400 / ERC-3643 compliant)
 *
 * ERC-1400 Features:
 *   - Partitions: LOCKED (primary lockup), VESTING, TRADEABLE
 *   - Transfer restrictions with ERC-1066 reason codes
 *   - Operator authorisation
 *   - Document management (prospectus, legal agreements)
 *   - Forced transfers for regulatory compliance
 *   - Issuance / redemption lifecycle
 *
 * MAS SFA Compliance:
 *   - Identity registry check on every transfer
 *   - ASEAN geo-fencing via country allow-list
 *   - 6-month lock-up on primary issuance
 *   - Accredited investor tier checks
 */
contract SURAToken is ERC20, ERC20Pausable, AccessControl, ReentrancyGuard, ISURAInvestable {

    bytes32 public constant COMPLIANCE_ROLE = keccak256("COMPLIANCE_ROLE");
    bytes32 public constant ISSUER_ROLE     = keccak256("ISSUER_ROLE");
    bytes32 public constant AGENT_ROLE      = keccak256("AGENT_ROLE");

    // ERC-1400 Partitions
    bytes32 public constant PARTITION_LOCKED    = keccak256("LOCKED");
    bytes32 public constant PARTITION_VESTING   = keccak256("VESTING");
    bytes32 public constant PARTITION_TRADEABLE = keccak256("TRADEABLE");

    // ERC-1066 Transfer Reason Codes
    bytes1 public constant CODE_SUCCESS         = 0x51;
    bytes1 public constant CODE_COMPLIANCE_FAIL = 0x50;
    bytes1 public constant CODE_NOT_VERIFIED    = 0x56;
    bytes1 public constant CODE_TOKENS_LOCKED   = 0x55;
    bytes1 public constant CODE_INSUFFICIENT    = 0x52;
    bytes1 public constant CODE_PAUSED          = 0x54;

    struct Document {
        bytes32 docHash;
        string  uri;
        uint48  updatedAt;
    }
    mapping(bytes32 => Document) private _documents;
    bytes32[] private _documentNames;

    struct STOConfig {
        string  name;
        string  symbol;
        string  assetType;
        string  assetDescription;
        uint256 targetRaise;
        uint256 tokenPrice;
        uint256 maxSupply;
        uint256 minInvestment;
        uint16[] allowedCountries;
        uint48  closingDate;
        uint48  lockupPeriod;
        address issuer;
        address treasury;
        uint16  feeBps;
    }

    STOConfig private _config;
    bool public offeringClosed;
    bool public redemptionEnabled;
    string public pauseReason;

    IIdentityRegistry public immutable identityRegistry;
    IERC20 public immutable usdc;

    mapping(address => mapping(bytes32 => uint256)) private _partitionBalances;
    mapping(bytes32 => uint256) private _partitionTotalSupply;
    mapping(address => uint48)  private _lockupExpiry;
    mapping(address => uint256) private _frozenTokens;
    mapping(address => bool)    private _isInvestor;
    address[] private _investorList;
    uint256 private _investorCount;
    uint256 private _totalRaised;

    mapping(address => mapping(address => bool)) private _operators;
    mapping(bytes32 => mapping(address => mapping(address => bool))) private _partitionOperators;

    uint256 private _distributionIndex;
    mapping(address => uint256) private _investorIndex;
    mapping(address => uint256) private _pendingClaims;

    event Issued(address indexed operator, address indexed to, uint256 indexed value, bytes data);
    event Redeemed(address indexed operator, address indexed from, uint256 indexed value, bytes data);
    event IssuedByPartition(bytes32 indexed partition, address indexed to, uint256 indexed value);
    event TransferByPartition(bytes32 indexed fromPartition, address indexed from, address indexed to, uint256 value);
    event TokensLocked(address indexed investor, uint256 indexed amount, uint48 indexed until);
    event TokensUnlocked(address indexed investor, uint256 indexed amount);
    event TokensFrozen(address indexed investor, uint256 amount);
    event TokensUnfrozen(address indexed investor, uint256 amount);
    event ForcedTransfer(address indexed from, address indexed to, uint256 amount, string reason);
    event TokensRecovered(address indexed lostWallet, address indexed newWallet, uint256 amount);
    event DocumentUpdated(bytes32 indexed name, string uri, bytes32 docHash);
    event OfferingClosed(uint256 totalRaised, uint256 totalTokens);
    event RedemptionEnabled();
    event RedemptionFundDeposited(address indexed depositor, uint256 indexed amount); // H-04 FIX
    event DustSwept(address indexed to, uint256 amount);                       // M-03 FIX
    event DistributionProcessed(uint256 indexed totalAmount, uint256 perToken, uint48 indexed timestamp);
    event Investment(address indexed investor, uint256 indexed usdcAmount, uint256 tokens);
    event OperatorAuthorised(address indexed operator, address indexed tokenHolder);
    event OperatorRevoked(address indexed operator, address indexed tokenHolder);
    event STOPaused(string reason);
    event STOResumed();

    constructor(
        STOConfig memory config,
        address identityRegistry_,
        address usdc_,
        address admin,
        address complianceOfficer
    ) ERC20(config.name, config.symbol) {
        _config = config;
        identityRegistry = IIdentityRegistry(identityRegistry_);
        usdc = IERC20(usdc_);
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(COMPLIANCE_ROLE, admin);
        _grantRole(COMPLIANCE_ROLE, complianceOfficer);
        _grantRole(ISSUER_ROLE, config.issuer);
        _grantRole(AGENT_ROLE, admin);
    }

    // Document Management (ERC-1400)
    function setDocument(bytes32 docName, string calldata uri, bytes32 docHash)
        external onlyRole(ISSUER_ROLE)
    {
        if (_documents[docName].updatedAt == 0) _documentNames.push(docName);
        _documents[docName] = Document({ docHash: docHash, uri: uri, updatedAt: uint48(block.timestamp) });
        emit DocumentUpdated(docName, uri, docHash);
    }

    function getDocument(bytes32 docName)
        external view returns (string memory uri, bytes32 docHash, uint48 updatedAt)
    {
        Document storage d = _documents[docName];
        return (d.uri, d.docHash, d.updatedAt);
    }

    function getAllDocuments() external view returns (bytes32[] memory) {
        return _documentNames;
    }

    // Partition Balances
    function balanceOfByPartition(bytes32 partition, address tokenHolder) external view returns (uint256) {
        return _partitionBalances[tokenHolder][partition];
    }

    function partitionsOf(address tokenHolder)
        external view returns (bytes32[] memory partitions, uint256[] memory amounts)
    {
        partitions = new bytes32[](3);
        amounts    = new uint256[](3);
        partitions[0] = PARTITION_LOCKED;    amounts[0] = _partitionBalances[tokenHolder][PARTITION_LOCKED];
        partitions[1] = PARTITION_VESTING;   amounts[1] = _partitionBalances[tokenHolder][PARTITION_VESTING];
        partitions[2] = PARTITION_TRADEABLE; amounts[2] = _partitionBalances[tokenHolder][PARTITION_TRADEABLE];
    }

    function totalSupplyByPartition(bytes32 partition) external view returns (uint256) {
        return _partitionTotalSupply[partition];
    }

    // Operator Management
    function authoriseOperator(address operator) external {
        _operators[msg.sender][operator] = true;
        emit OperatorAuthorised(operator, msg.sender);
    }

    function revokeOperator(address operator) external {
        _operators[msg.sender][operator] = false;
        emit OperatorRevoked(operator, msg.sender);
    }

    function isOperator(address operator, address tokenHolder) public view returns (bool) {
        return _operators[tokenHolder][operator] || hasRole(AGENT_ROLE, operator);
    }

    function authoriseOperatorByPartition(bytes32 partition, address operator) external {
        _partitionOperators[partition][msg.sender][operator] = true;
    }

    function isOperatorForPartition(bytes32 partition, address operator, address tokenHolder)
        public view returns (bool)
    {
        return _partitionOperators[partition][tokenHolder][operator] || isOperator(operator, tokenHolder);
    }

    // Investment (primary issuance into LOCKED partition)
    function invest(address investor, uint256 usdcAmount)
        external onlyRole(AGENT_ROLE) whenNotPaused nonReentrant
    {
        require(!offeringClosed, "SURA: offering closed");
        require(block.timestamp <= _config.closingDate, "SURA: offering expired");
        require(identityRegistry.canTransfer(address(0), investor), "SURA: investor not verified");

        uint256 tokens = (usdcAmount * 1e18) / _config.tokenPrice;
        require(tokens >= _config.minInvestment, "SURA: below minimum");
        require(totalSupply() + tokens <= _config.maxSupply, "SURA: exceeds max supply");

        uint256 fee        = (usdcAmount * _config.feeBps) / 10000;
        uint256 netProceeds = usdcAmount - fee;

        require(usdc.transferFrom(msg.sender, address(this), usdcAmount), "SURA: USDC pull failed");
        require(usdc.transfer(_config.treasury, fee), "SURA: fee transfer failed");
        require(usdc.transfer(_config.issuer, netProceeds), "SURA: proceeds transfer failed");

        _updateInvestorIndex(investor);
        _mintByPartition(PARTITION_LOCKED, investor, tokens);

        uint48 expiry = uint48(block.timestamp) + _config.lockupPeriod;
        if (_lockupExpiry[investor] < expiry) _lockupExpiry[investor] = expiry;

        _totalRaised += usdcAmount;
        if (!_isInvestor[investor]) {
            _isInvestor[investor] = true;
            _investorList.push(investor);
            ++_investorCount;
        }

        emit Investment(investor, usdcAmount, tokens);
        emit IssuedByPartition(PARTITION_LOCKED, investor, tokens);
        emit TokensLocked(investor, tokens, expiry);
    }

    // Unlock tokens after lockup period expires
    function unlockTokens(address investor) external {
        require(block.timestamp >= _lockupExpiry[investor], "SURA: lockup not expired");
        uint256 locked = _partitionBalances[investor][PARTITION_LOCKED];
        require(locked > 0, "SURA: no locked tokens");
        _partitionBalances[investor][PARTITION_LOCKED]    -= locked;
        _partitionTotalSupply[PARTITION_LOCKED]           -= locked;
        _partitionBalances[investor][PARTITION_TRADEABLE] += locked;
        _partitionTotalSupply[PARTITION_TRADEABLE]        += locked;
        emit TokensUnlocked(investor, locked);
        emit TransferByPartition(PARTITION_LOCKED, investor, investor, locked);
    }

    function lockupExpiry(address investor) external view returns (uint48) {
        return _lockupExpiry[investor];
    }

    // Transfer By Partition (only TRADEABLE)
    function transferByPartition(bytes32 partition, address to, uint256 value, bytes calldata /*data*/)
        external whenNotPaused nonReentrant returns (bytes32)
    {
        require(partition == PARTITION_TRADEABLE, "SURA: only TRADEABLE");
        (bytes1 code, string memory reason) = _checkTransfer(msg.sender, to, value);
        require(code == CODE_SUCCESS, reason);
        _updateInvestorIndex(msg.sender);
        _updateInvestorIndex(to);
        _transferByPartition(partition, msg.sender, to, value);
        emit TransferByPartition(partition, msg.sender, to, value);
        return partition;
    }

    function operatorTransferByPartition(
        bytes32 partition, address from, address to, uint256 value,
        bytes calldata /*data*/, bytes calldata /*operatorData*/
    ) external whenNotPaused nonReentrant returns (bytes32) {
        require(isOperatorForPartition(partition, msg.sender, from), "SURA: not authorised operator");
        require(partition == PARTITION_TRADEABLE, "SURA: only TRADEABLE");
        (bytes1 code, string memory reason) = _checkTransfer(from, to, value);
        require(code == CODE_SUCCESS, reason);
        _updateInvestorIndex(from);
        _updateInvestorIndex(to);
        _transferByPartition(partition, from, to, value);
        emit TransferByPartition(partition, from, to, value);
        return partition;
    }

    function canTransferByPartition(bytes32 partition, address from, address to, uint256 value, bytes calldata /*data*/)
        external view returns (bytes1 code, bytes32, string memory reason)
    {
        if (paused()) return (CODE_PAUSED, partition, "STO is paused");
        if (partition != PARTITION_TRADEABLE) return (CODE_TOKENS_LOCKED, partition, "Not in TRADEABLE partition");
        (bytes1 c, string memory r) = _checkTransfer(from, to, value);
        return (c, partition, r);
    }

    function _checkTransfer(address from, address to, uint256 value)
        internal view returns (bytes1, string memory)
    {
        if (!identityRegistry.isVerified(to)) return (CODE_NOT_VERIFIED, "Receiver not KYC verified");
        if (from != address(0) && !identityRegistry.isVerified(from)) return (CODE_NOT_VERIFIED, "Sender not KYC verified");
        if (_partitionBalances[from][PARTITION_TRADEABLE] < value + _frozenTokens[from])
            return (CODE_INSUFFICIENT, "Insufficient tradeable balance");
        return (CODE_SUCCESS, "");
    }

    // Compliance
    function freezeTokens(address investor, uint256 amount) external onlyRole(COMPLIANCE_ROLE) {
        require(balanceOf(investor) >= _frozenTokens[investor] + amount, "SURA: insufficient balance");
        _frozenTokens[investor] += amount;
        emit TokensFrozen(investor, amount);
    }

    function unfreezeTokens(address investor, uint256 amount) external onlyRole(COMPLIANCE_ROLE) {
        require(_frozenTokens[investor] >= amount, "SURA: insufficient frozen");
        _frozenTokens[investor] -= amount;
        emit TokensUnfrozen(investor, amount);
    }

    function forcedTransfer(address from, address to, uint256 amount, string calldata reason)
        external onlyRole(COMPLIANCE_ROLE)
    {
        require(balanceOf(from) >= amount, "SURA: insufficient balance");
        _updateInvestorIndex(from);
        _updateInvestorIndex(to);
        uint256 locked = _partitionBalances[from][PARTITION_LOCKED];
        if (locked >= amount) {
            _transferByPartition(PARTITION_LOCKED, from, to, amount);
        } else if (locked > 0) {
            _transferByPartition(PARTITION_LOCKED, from, to, locked);
            _transferByPartition(PARTITION_TRADEABLE, from, to, amount - locked);
        } else {
            _transferByPartition(PARTITION_TRADEABLE, from, to, amount);
        }
        emit ForcedTransfer(from, to, amount, reason);
    }

    function recoverTokens(address lostWallet, address newWallet) external onlyRole(COMPLIANCE_ROLE) {
        require(identityRegistry.isVerified(newWallet), "SURA: new wallet not verified");
        uint256 amount = balanceOf(lostWallet);
        require(amount > 0, "SURA: no tokens to recover");
        _updateInvestorIndex(lostWallet);
        _updateInvestorIndex(newWallet);
        uint256 locked    = _partitionBalances[lostWallet][PARTITION_LOCKED];
        uint256 vesting   = _partitionBalances[lostWallet][PARTITION_VESTING];
        uint256 tradeable = _partitionBalances[lostWallet][PARTITION_TRADEABLE];
        if (locked > 0)    _transferByPartition(PARTITION_LOCKED, lostWallet, newWallet, locked);
        if (vesting > 0)   _transferByPartition(PARTITION_VESTING, lostWallet, newWallet, vesting);
        if (tradeable > 0) _transferByPartition(PARTITION_TRADEABLE, lostWallet, newWallet, tradeable);
        if (_lockupExpiry[newWallet] < _lockupExpiry[lostWallet])
            _lockupExpiry[newWallet] = _lockupExpiry[lostWallet];
        _pendingClaims[newWallet] += _pendingClaims[lostWallet];
        _pendingClaims[lostWallet] = 0;
        emit TokensRecovered(lostWallet, newWallet, amount);
    }

    // Lifecycle
    function pause(string calldata reason) external onlyRole(COMPLIANCE_ROLE) {
        pauseReason = reason;
        _pause();
        emit STOPaused(reason);
    }

    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        pauseReason = "";
        _unpause();
        emit STOResumed();
    }

    function closeOffering() external onlyRole(ISSUER_ROLE) {
        require(!offeringClosed, "SURA: already closed");
        offeringClosed = true;
        emit OfferingClosed(_totalRaised, totalSupply());
    }

    // H-04 FIX: Issuer must deposit USDC before redemption can be enabled.
    // Without this, redeem() always reverts because contract holds no USDC after investment.
    function depositRedemptionFund(uint256 amount) external onlyRole(ISSUER_ROLE) {
        require(amount > 0, "SURA: zero amount");
        require(usdc.transferFrom(msg.sender, address(this), amount), "SURA: deposit failed");
        emit RedemptionFundDeposited(msg.sender, amount);
    }

    function enableRedemption() external onlyRole(DEFAULT_ADMIN_ROLE) {
        redemptionEnabled = true;
        emit RedemptionEnabled();
    }

    function redeem(uint256 amount) external nonReentrant whenNotPaused {
        require(redemptionEnabled, "SURA: redemption not enabled");
        require(_partitionBalances[msg.sender][PARTITION_TRADEABLE] >= amount, "SURA: insufficient tradeable");
        require(identityRegistry.isVerified(msg.sender), "SURA: not verified");
        uint256 usdcAmount = (amount * _config.tokenPrice) / 1e18;
        require(usdc.balanceOf(address(this)) >= usdcAmount, "SURA: insufficient USDC");
        _updateInvestorIndex(msg.sender);
        _burnByPartition(PARTITION_TRADEABLE, msg.sender, amount);
        require(usdc.transfer(msg.sender, usdcAmount), "SURA: USDC transfer failed");
        emit Redeemed(msg.sender, msg.sender, amount, "");
    }

    // Distributions
    function processDistribution(uint256 totalUSDC) external onlyRole(ISSUER_ROLE) nonReentrant {
        require(totalSupply() > 0, "SURA: no tokens outstanding");
        require(totalUSDC > 0, "SURA: zero distribution");
        require(usdc.transferFrom(msg.sender, address(this), totalUSDC), "SURA: USDC transfer failed");
        uint256 increment = (totalUSDC * 1e18) / totalSupply();
        _distributionIndex += increment;
        emit DistributionProcessed(totalUSDC, increment, uint48(block.timestamp));
    }

    function claimDistribution() external nonReentrant whenNotPaused {
        _updateInvestorIndex(msg.sender);
        uint256 amount = _pendingClaims[msg.sender];
        require(amount > 0, "SURA: nothing to claim");
        _pendingClaims[msg.sender] = 0;
        require(usdc.transfer(msg.sender, amount), "SURA: claim transfer failed");
    }

    function pendingDistribution(address investor) external view returns (uint256) {
        uint256 delta = _distributionIndex - _investorIndex[investor];
        return _pendingClaims[investor] + (balanceOf(investor) * delta) / 1e18;
    }

    // ERC-20 override — enforce compliance
    function _update(address from, address to, uint256 amount)
        internal override(ERC20, ERC20Pausable)
    {
        if (from != address(0) && to != address(0)) {
            require(identityRegistry.canTransfer(from, to), "SURA: transfer not compliant");
            require(balanceOf(from) - _frozenTokens[from] >= amount, "SURA: insufficient unfrozen");
            _updateInvestorIndex(from);
            _updateInvestorIndex(to);
        }
        super._update(from, to, amount);
    }

    // Internal helpers
    function _mintByPartition(bytes32 partition, address to, uint256 amount) internal {
        _mint(to, amount);
        _partitionBalances[to][partition]  += amount;
        _partitionTotalSupply[partition]   += amount;
    }

    function _burnByPartition(bytes32 partition, address from, uint256 amount) internal {
        _burn(from, amount);
        _partitionBalances[from][partition] -= amount;
        _partitionTotalSupply[partition]    -= amount;
    }

    function _transferByPartition(bytes32 partition, address from, address to, uint256 amount) internal {
        _transfer(from, to, amount);
        _partitionBalances[from][partition] -= amount;
        _partitionBalances[to][partition]   += amount;
    }

    function _updateInvestorIndex(address investor) internal {
        uint256 delta = _distributionIndex - _investorIndex[investor];
        if (delta > 0 && balanceOf(investor) > 0)
            _pendingClaims[investor] += (balanceOf(investor) * delta) / 1e18;
        _investorIndex[investor] = _distributionIndex;
    }

    // M-03 FIX: recover USDC dust accumulated from distribution rounding
    // Small token holders may accrue zero due to integer division — this recovers stranded USDC
    function sweepDust(address to) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(to != address(0), "SURA: zero address");
        uint256 balance = usdc.balanceOf(address(this));
        require(balance > 0, "SURA: nothing to sweep");
        require(usdc.transfer(to, balance), "SURA: sweep failed");
        emit DustSwept(to, balance);
    }

    // Read functions
    function getConfig()                  external view returns (STOConfig memory) { return _config; }
    function frozenBalance(address i)     external view returns (uint256) { return _frozenTokens[i]; }
    function isFrozen(address i)          external view returns (bool)    { return _frozenTokens[i] > 0; }
    function totalRaised()                external view returns (uint256) { return _totalRaised; }
    function investorCount()              external view returns (uint256) { return _investorCount; }
    function getInvestorAt(uint256 index) external view returns (address) { return _investorList[index]; }
    function decimals() public pure override returns (uint8) { return 18; }
}

